import React, { useEffect, useRef } from 'react';
import { Input, SearchInput, MoneyInput } from '@linm-soft/common-components';
import { useLinesGridMessageTitles } from '../../../../../hooks/useLinesGridMessageTitles';
import { useSelectedLineRowSync } from '../../../../../hooks/useSelectedLineRowSync';
import { AccountSearchInput, erpFinanceAccountSearchApi } from '../../../../../components/search';
import { formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import {
  DEPARTMENT_PLACEHOLDER_OPTION,
  resolveDepartmentName,
} from '../../../../../utils/departmentField';
import type { TamUngFormViewModel } from '../hooks/useTamUngFormController';

function isLineRowFieldTarget(target: HTMLElement): boolean {
  return !!target.closest(
    'input, textarea, select, button, a, [role="option"], [role="listbox"]',
  );
}

export const TamUngLinesSection: React.FC<{ vm: TamUngFormViewModel }> = ({ vm }) => {
  const {
    labels,
    tid,
    styles: df,
    viewSectionClass,
    lines,
    lineRows,
    fieldErrors,
    updateLine,
    removeLine,
    handleAddLine,
    handleCopyLine,
    handleSelectLine,
    selectedLineIndex,
    highlightLineId,
    isReadOnly,
    isViewMode,
    ph,
    searchDisabled,
    fieldLockProps,
    departmentSearchConfig,
    departmentOptions,
  } = vm;

  const sectionRef = useRef<HTMLDivElement>(null);
  const rowRefs = useRef<(HTMLTableRowElement | null)[]>([]);

  useSelectedLineRowSync(rowRefs, selectedLineIndex, {
    sectionRef,
    isFieldTarget: isLineRowFieldTarget,
  });

  useLinesGridMessageTitles(sectionRef, [fieldErrors, lines.length]);

  useEffect(() => {
    const root = sectionRef.current;
    if (!root) return undefined;

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
      const target = e.target as HTMLElement;
      if (isLineRowFieldTarget(target)) return;
      if (!root.contains(target)) return;

      e.preventDefault();
      if (e.key === 'ArrowDown') {
        handleSelectLine(Math.min(selectedLineIndex + 1, lines.length - 1));
      } else {
        handleSelectLine(Math.max(selectedLineIndex - 1, 0));
      }
    };

    root.addEventListener('keydown', onKeyDown);
    return () => root.removeEventListener('keydown', onKeyDown);
  }, [handleSelectLine, lines.length, selectedLineIndex]);

  const focusRow = (idx: number) => {
    rowRefs.current[idx]?.focus({ preventScroll: true });
  };

  return (
    <div
      ref={sectionRef}
      className={[df.section, viewSectionClass].filter(Boolean).join(' ')}
      id={tid('section-lines')}
      data-testid={tid('section-lines')}
    >
      <h2 className={df.sectionTitle}>{labels.sectionLines}</h2>
      <div className={df.tableWrapper}>
        <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
          <thead>
            <tr>
              <th className={df.thAccount}>{labels.debitAccount}</th>
              <th className={df.thAmount}>{labels.amount}</th>
              <th className={df.thCostCenter}>{labels.costCenter}</th>
              <th className={df.thDesc}>{labels.lineDescription}</th>
              {!isReadOnly && <th className={df.thDel} />}
            </tr>
          </thead>
          <tbody>
            {lineRows.map((lineState, idx) => {
              const line = lines[idx];
              if (!line) return null;
              const isSelected = selectedLineIndex === idx;
              const isHighlight = highlightLineId === lineState.lineId;
              const rowClass = [
                isSelected ? df.lineRowSelected : '',
                isHighlight ? df.lineRowHighlight : '',
                isHighlight ? df.lineRowEnter : '',
              ].filter(Boolean).join(' ');

              return (
                <tr
                  key={lineState.lineId}
                  ref={el => { rowRefs.current[idx] = el; }}
                  className={[df.lineRow, rowClass].filter(Boolean).join(' ')}
                  data-testid={tid(`line-${idx}`)}
                  tabIndex={isSelected ? 0 : -1}
                  aria-selected={isSelected}
                  onClick={e => {
                    handleSelectLine(idx);
                    const target = e.target as HTMLElement;
                    if (isLineRowFieldTarget(target)) return;
                    focusRow(idx);
                  }}
                  onKeyDown={e => {
                    if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
                    const target = e.target as HTMLElement;
                    if (isLineRowFieldTarget(target)) return;
                    e.preventDefault();
                    if (e.key === 'ArrowDown' && idx < lines.length - 1) {
                      handleSelectLine(idx + 1);
                    } else if (e.key === 'ArrowUp' && idx > 0) {
                      handleSelectLine(idx - 1);
                    }
                  }}
                >
                  <td
                    id={tid(`line-${idx}-account`)}
                    data-testid={tid(`line-${idx}-account`)}
                    data-label={labels.debitAccount}
                  >
                    <AccountSearchInput
                      api={erpFinanceAccountSearchApi}
                      className={df.lineAccountSearch}
                      value={line.accountCode}
                      primaryDisplay={formatAccountDisplay(line.accountCode, line.accountName)}
                      error={fieldErrors.lines?.[idx]?.accountCode}
                      onChange={a => updateLine(idx, { accountCode: a.code, accountName: a.name })}
                      onClear={() => updateLine(idx, { accountCode: '', accountName: '' })}
                      showLabel={false}
                      showSecondaryInput={false}
                      placeholder={ph(labels.phDebitAccount)}
                      disabled={searchDisabled}
                    />
                  </td>
                  <td
                    id={tid(`line-${idx}-amount`)}
                    data-testid={tid(`line-${idx}-amount`)}
                    data-label={labels.amount}
                  >
                    <MoneyInput
                      value={Number(line.amount)}
                      error={fieldErrors.lines?.[idx]?.debitAmount}
                      onChange={amount => updateLine(idx, { amount })}
                      {...fieldLockProps}
                    />
                  </td>
                  <td data-testid={tid(`line-${idx}-costCenter`)} data-label={labels.costCenter}>
                    <SearchInput
                      config={departmentSearchConfig}
                      className={isViewMode ? df.searchViewOnly : df.lineAccountSearch}
                      value={line.costCenterCode}
                      primaryDisplay={line.costCenterCode}
                      secondaryDisplay={resolveDepartmentName(line.costCenterCode, departmentOptions)}
                      onChange={d => updateLine(idx, { costCenterCode: d.code })}
                      onClear={() => updateLine(idx, { costCenterCode: '' })}
                      showLabel={false}
                      placeholder={ph(DEPARTMENT_PLACEHOLDER_OPTION.label)}
                      disabled={searchDisabled}
                    />
                  </td>
                  <td data-testid={tid(`line-${idx}-description`)} data-label={labels.lineDescription}>
                    <Input
                      value={line.description}
                      onChange={e => updateLine(idx, { description: e.target.value })}
                      placeholder={ph(labels.phLineDescription)}
                      {...fieldLockProps}
                    />
                  </td>
                  {!isReadOnly && (
                    <td>
                      <button
                        type="button"
                        className={df.btnDeleteLine}
                        onClick={e => {
                          e.stopPropagation();
                          removeLine(idx);
                        }}
                        title="Xóa dòng"
                        data-testid={tid(`line-${idx}-delete`)}
                      >
                        <i className="fas fa-trash-alt" aria-hidden="true" />
                      </button>
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      {!isReadOnly && (
        <div className={df.linesActions}>
          <button
            type="button"
            className={df.btnAddLine}
            data-testid={tid('add-line-btn')}
            onClick={handleAddLine}
          >
            {labels.addLine}
          </button>
          <button
            type="button"
            className={df.btnCopyLine}
            data-testid={tid('copy-line-btn')}
            onClick={handleCopyLine}
            disabled={lines.length === 0}
          >
            {labels.copyLine}
          </button>
        </div>
      )}
    </div>
  );
};
